const first = $input.first();
const targets = first?.json?.targets;

if (!Array.isArray(targets) || targets.length === 0) {
  throw new Error('sub-channel-router: targets is missing or empty.');
}

const email_targets = [];
const form_targets = [];
const excluded_targets = [];

for (const t of targets) {
  if (t.normalized_status === 'active' && t.validated_channel === 'email') {
    email_targets.push(t);
  } else if (t.normalized_status === 'active' && t.validated_channel === 'form') {
    form_targets.push(t);
  } else {
    excluded_targets.push(t);
  }
}

return [
  {
    json: {
      email_targets,
      form_targets,
      excluded_targets
    }
  }
];
